mapper.select:
SELECT c.id, c.user_id as userId, c.product_id as productId, c.quantity,
       c.selected_color as selectedColor, c.selected_storage as selectedStorage,
       c.insurance_type as insuranceType, c.insurance_price as insurancePrice,
       c.unit_price as unitPrice, c.added_at as addedAt,
       p.name as productName, p.price, p.image_url as imageUrl, p.stock, p.category
FROM cart_items c
LEFT JOIN products p ON c.product_id = p.id
WHERE c.user_id = #{userId} AND c.product_id = #{productId}
  AND c.selected_color = #{selectedColor}
  AND c.selected_storage = #{selectedStorage}
  AND c.insurance_type = #{insuranceType}

mapper.update:
UPDATE cart_items 
SET quantity = quantity + #{quantity}
WHERE id = #{id}
